import React, { useState } from 'react';
import { BrowserRouter, Routes, Route, Link, Outlet, Redirect } from 'react-router-dom';
import Purchases from './pages/Purchases.js';
import Vendors from './pages/Vendors.js';
import Outflow from './pages/Outflow.js';
import MaterialList from './pages/MaterialList.js';
import Projects from './pages/Projects.js';
import ProjectOutflows from './pages/ProjectOutflows.js';
import Stock from './pages/Stock.js';
import Login from './Login'; // Import the Login component


import './App.css'; // Import custom CSS for App component

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  const handleLogin = (token) => {
    // Handle token storage securely (e.g., in cookies or local storage)
    setIsAuthenticated(true);
  };

  if (!isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }



  return (
    <div
      className={'App'}>
      <BrowserRouter>
        <nav className="sidebar">
          <ul className="navbar-nav">
            <li className="nav-item">
              <Link to="/Purchases" className="nav-link">
                <span>Inflow</span>
              </Link>
            </li>
            <li className="nav-item">
              <Link to="/Outflow" className="nav-link">
                <span>Outflow</span>
              </Link>
            </li>
            <li className="nav-item">
              <Link to="/MaterialList" className="nav-link">
                <span>Material List</span>
              </Link>
            </li>
            <li className="nav-item">
              <Link to="/Vendors" className="nav-link">
                <span>Vendor List</span>
              </Link>
            </li>
            <li className="nav-item">
              <Link to="/Projects" className="nav-link">
                <span>Project List</span>
              </Link>
            </li>
            <li className="nav-item">
              <Link to="/Stock" className="nav-link">
                <span>Stock</span>
              </Link>
            </li>
          </ul>
        </nav>
        <main className="content">
          <header className="header">
            <h1 className="header-title">ROBBIE</h1>
          </header>
          <Routes>
          <Route path="/Purchases" element={<ProtectedRoute><Purchases /></ProtectedRoute>} />
            <Route path="/Outflow" element={<Outflow />} />
            <Route path="/Vendors" element={<Vendors />} />
            <Route path="/MaterialList" element={<MaterialList />} />
            <Route path="/Projects" element={<Projects />} />
            <Route path="/ProjectOutflows" element={<ProjectOutflows />} />
            <Route path="/Stock" element={<Stock />} />

            {/* Add other routes for different pages */}
          </Routes>
        </main>
      </BrowserRouter>
    </div>
  );
}

function ProtectedRoute(props) {
  // This is a simple example. In a real-world scenario, you might check for a token or other authentication method.
  if (!isAuthenticated) {
    return <Redirect to="/login" />;
  }

  return <Outlet {...props} />;
}

export default App;
